'use client';

import React, { useRef, useState, useEffect } from 'react';
import { motion, useScroll, useTransform, useSpring } from 'framer-motion';
import { products } from '../data/products';

export default function ProductDetailsScroller({ selected }: { selected: number }) {
  const product = products[selected] || products[0];
  const ref = useRef<HTMLDivElement>(null);
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 768);
    handleResize(); // Component mounts on client side mostly, but for safety.
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const { scrollYProgress } = useScroll({
    target: ref,
    offset: ["start start", "end end"]
  });

  const smoothProgress = useSpring(scrollYProgress, { stiffness: 60, damping: 20, restDelta: 0.001 });

  // Mobile and Desktop specific transforms
  const xLeft = isMobile ? "-15%" : "-30%";
  const xRight = isMobile ? "15%" : "30%";

  const bottleScale = useTransform(smoothProgress, [0, 0.2, 0.5, 0.8, 1], [1, isMobile ? 0.7 : 0.9, isMobile ? 0.7 : 0.9, 1, 1]);
  const bottleX = useTransform(smoothProgress, [0, 0.2, 0.5, 0.8, 1], ["0%", xLeft, xRight, "0%", "0%"]);
  const bottleY = useTransform(smoothProgress, [0, 0.2, 0.5, 0.8, 1], ["0%", "5%", "-5%", "0%", "0%"]);
  const bottleRotateY = useTransform(smoothProgress, [0, 0.2, 0.5, 0.8, 1], [0, -25, 25, 0, 0]);
  const bottleRotateZ = useTransform(smoothProgress, [0, 0.2, 0.5, 0.8, 1], [0, -5, 5, 0, 0]);

  // Text 1 (Right Side)
  const text1Opacity = useTransform(smoothProgress, [0.1, 0.2, 0.35, 0.45], [0, 1, 1, 0]);
  const text1Y = useTransform(smoothProgress, [0.1, 0.2, 0.35, 0.45], [100, 0, 0, -100]);

  // Text 2 (Left Side)
  const text2Opacity = useTransform(smoothProgress, [0.4, 0.5, 0.65, 0.75], [0, 1, 1, 0]);
  const text2Y = useTransform(smoothProgress, [0.4, 0.5, 0.65, 0.75], [100, 0, 0, -100]);

  return (
    <div ref={ref} className="relative w-full h-[400vh] bg-[#050505]">
      <div className="sticky top-0 h-screen w-full flex items-center justify-center overflow-hidden perspective-[1000px]">
        
        {/* Glowing Background */}
        <motion.div 
           className="absolute w-[80vw] md:w-[60vh] h-[80vw] md:h-[60vh] rounded-full blur-[120px] opacity-20 pointer-events-none"
           style={{ backgroundColor: product.color }}
           animate={{ scale: [1, 1.2, 1], opacity: [0.1, 0.3, 0.1] }}
           transition={{ duration: 5, repeat: Infinity, ease: "easeInOut" }}
        />

        {/* Text Area 1: Product Features */}
        <motion.div 
          className="absolute z-20 w-full md:w-[40%] right-0 md:right-[5%] px-6 md:px-0 text-center md:text-left pointer-events-none"
          style={{ opacity: text1Opacity, y: text1Y }}
        >
          <div className="bg-black/40 backdrop-blur-xl border border-white/10 p-6 md:p-10 rounded-3xl shadow-2xl inline-block w-full max-w-[400px] ml-auto">
            <h2 className="text-3xl md:text-5xl font-bold font-sans tracking-tight mb-6" style={{ color: product.color }}>
              Ultimate Protection
            </h2>
            <div className="space-y-4 text-left">
              {product.features.map((f, i) => (
                 <div key={i} className="flex gap-4 items-center bg-white/5 border border-white/5 p-4 rounded-xl">
                   <div className="w-3 h-3 rounded-full flex-shrink-0" style={{ backgroundColor: product.color, boxShadow: `0 0 10px ${product.color}` }} />
                   <p className="text-white font-medium text-lg">{f}</p>
                 </div>
              ))}
            </div>
          </div>
        </motion.div>

        {/* Text Area 2: Product Specs */}
        <motion.div 
          className="absolute z-20 w-full md:w-[40%] left-0 md:left-[5%] px-6 md:px-0 text-center md:text-left pointer-events-none"
          style={{ opacity: text2Opacity, y: text2Y }}
        >
          <div className="bg-black/40 backdrop-blur-xl border border-white/10 p-6 md:p-10 rounded-3xl shadow-2xl inline-block w-full max-w-[420px]">
            <h2 className="text-3xl md:text-5xl font-bold font-sans tracking-tight mb-6 text-white" style={{ textShadow: `0 0 20px ${product.color}40` }}>
              Advanced Formula
            </h2>
            <p className="text-gray-300 text-lg mb-8 leading-relaxed">
              {product.description}
            </p>
            <div className="flex flex-col gap-4">
              <div className="flex items-center gap-4">
                  <span className="text-gray-400 uppercase tracking-widest text-sm font-bold w-24">Volume</span>
                  <span className="font-bold text-xl py-2 px-6 rounded-full" style={{ backgroundColor: product.color, color: '#000' }}>
                      {product.volume}
                  </span>
              </div>
              <div className="flex items-center gap-4">
                  <span className="text-gray-400 uppercase tracking-widest text-sm font-bold w-24">Type</span>
                  <span className="text-white font-bold opacity-80">{product.tagline}</span>
              </div>
            </div>
          </div>
        </motion.div>

        {/* Floating Bottle */}
        <motion.div 
          className="relative z-30 w-[70vw] md:w-[35vw] h-[60vh] md:h-[70vh] flex items-center justify-center transform-style-3d"
          style={{ 
            scale: bottleScale, 
            x: bottleX, 
            y: bottleY, 
            rotateY: bottleRotateY, 
            rotateZ: bottleRotateZ 
          }}
        >
            <motion.div 
              className="w-full h-full relative group"
              animate={{ y: [0, -15, 0] }}
              transition={{ repeat: Infinity, duration: 4, ease: "easeInOut" }}
            >
              <img 
                src={product.image} 
                alt={product.name}
                className="w-full h-full object-contain filter drop-shadow-2xl"
                style={{ filter: `drop-shadow(0 30px 40px ${product.color}50)` }}
              />
          </motion.div>
        </motion.div>

      </div>
    </div>
  );
}
